def authenticate_user(username, password):
    """Authenticate a user with username and password credentials."""
    user = db.find_user(username)
    if user is None:
        return AuthResult.user_not_found()
    if not verify_password(password, user.password_hash):
        return AuthResult.invalid_credentials()
    token = generate_session_token(user.id)
    return AuthResult.success(token)

def verify_password(plaintext, hashed):
    """Verify a plaintext password against a stored bcrypt hash."""
    import bcrypt
    return bcrypt.checkpw(plaintext.encode(), hashed.encode())

def generate_session_token(user_id):
    """Generate a cryptographically secure session token for the given user."""
    import secrets
    token = secrets.token_hex(32)
    session_store[token] = {'user_id': user_id, 'created_at': time.time()}
    return token

def invalidate_session(token):
    """Invalidate (logout) a session by removing the token from the store."""
    return session_store.pop(token, None) is not None

def check_permission(user_id, resource, action):
    """Check whether a user has permission to perform action on resource."""
    roles = get_user_roles(user_id)
    for role in roles:
        if role.allows(resource, action):
            return True
    return False

def get_user_roles(user_id):
    """Fetch all roles assigned to a user from the database."""
    return db.query('SELECT role FROM user_roles WHERE user_id = ?', (user_id,))

def require_auth(handler):
    """Decorator that enforces authentication before calling the handler."""
    def wrapper(request, *args, **kwargs):
        token = request.headers.get('Authorization')
        if token is None or not validate_token(token):
            return Response(status=401, body='Unauthorized')
        return handler(request, *args, **kwargs)
    return wrapper

def validate_token(token):
    """Return True if the token exists in the session store and has not expired."""
    session = session_store.get(token)
    if session is None:
        return False
    return time.time() - session['created_at'] < SESSION_TTL

def hash_password(plaintext):
    """Hash a plaintext password using bcrypt with a random salt."""
    import bcrypt
    salt = bcrypt.gensalt()
    return bcrypt.hashpw(plaintext.encode(), salt).decode()

function loadConfig(configPath: string): Config {
  /** Load configuration from disk and validate it. */
  const raw = fs.readFileSync(configPath, 'utf8');
  const parsed = JSON.parse(raw);
  return validateConfig(parsed);
}

function validateConfig(config: unknown): Config {
  /** Validate a raw parsed config object and throw if required fields are missing. */
  if (!config || typeof config !== 'object') {
    throw new ConfigError('Config must be a JSON object');
  }
  const c = config as Record<string, unknown>;
  if (!c.database) throw new ConfigError('Missing required field: database');
  if (!c.port) throw new ConfigError('Missing required field: port');
  return c as Config;
}

class ConfigError extends Error {
  /** Custom error type for configuration validation failures. */
  constructor(message: string) {
    super(message);
    this.name = 'ConfigError';
  }
}

function mergeWithDefaults(config: Partial<Config>): Config {
  /** Merge a partial config with the default values, user values taking priority. */
  return { ...DEFAULT_CONFIG, ...config };
}

function getDefaultConfig(): Config {
  /** Return the built-in default configuration values. */
  return { ...DEFAULT_CONFIG };
}

function loadEnvOverrides(config: Config): Config {
  /** Apply environment variable overrides to the config. DATABASE_URL and PORT are checked. */
  const overridden = { ...config };
  if (process.env.DATABASE_URL) overridden.database = process.env.DATABASE_URL;
  if (process.env.PORT) overridden.port = parseInt(process.env.PORT, 10);
  return overridden;
}

func FilterRecords(records []Record, predicate func(Record) bool) []Record {
	// FilterRecords applies predicate to each record and returns matching records.
	result := make([]Record, 0, len(records))
	for _, r := range records {
		if predicate(r) {
			result = append(result, r)
		}
	}
	return result
}

func TransformRecords(records []Record, fn func(Record) Record) []Record {
	// TransformRecords applies fn to each record, returning the transformed slice.
	result := make([]Record, len(records))
	for i, r := range records {
		result[i] = fn(r)
	}
	return result
}

func AggregateSum(records []Record, field string) float64 {
	// AggregateSum sums the numeric field across all records.
	var total float64
	for _, r := range records {
		total += r.GetFloat(field)
	}
	return total
}

func AggregateCount(records []Record) int {
	// AggregateCount returns the number of records in the slice.
	return len(records)
}

func RunPipeline(input []Record, stages []Stage) []Record {
	// RunPipeline applies each pipeline stage sequentially to the input records.
	result := input
	for _, stage := range stages {
		result = stage.Process(result)
	}
	return result
}

type Stage struct {
	// Stage represents one step in the data processing pipeline.
	Name    string
	Process func([]Record) []Record
}

func SortRecords(records []Record, field string, ascending bool) []Record {
	// SortRecords sorts records by the specified field in ascending or descending order.
	sorted := make([]Record, len(records))
	copy(sorted, records)
	sort.Slice(sorted, func(i, j int) bool {
		if ascending {
			return sorted[i].GetString(field) < sorted[j].GetString(field)
		}
		return sorted[i].GetString(field) > sorted[j].GetString(field)
	})
	return sorted
}
